import { cleanup } from "@testing-library/react";
import "@testing-library/jest-dom";
import type { RequestHandler } from "msw";
import { type SetupServer, setupServer } from "msw/node";
import { afterAll, afterEach, beforeAll } from "vitest";

/**
 * Configuration for the test utils.
 *
 * This config is used to configure the test utils to work with your specific project.
 * It is used to configure the MSW handlers and the providers to wrap the test components.
 * It is also used to configure the additional setup to run before all tests, after each test, and after all tests.
 */

export interface TestUtilsConfig {
  /**
   * Project-specific MSW handlers
   */
  handlers?: RequestHandler[];
  /**
   * Project-specific providers to wrap test components
   */
  providers?: React.ComponentType<{ children: React.ReactNode }>[];
  /**
   * Additional setup to run before all tests
   */
  beforeAll?: () => void | Promise<void>;
  /**
   * Additional setup to run after each test
   */
  afterEach?: () => void | Promise<void>;
  /**
   * Additional setup to run after all tests
   */
  afterAll?: () => void | Promise<void>;
}

let server: SetupServer;

export function setupTestUtils(config: TestUtilsConfig = {}) {
  // Setup MSW server with project-specific handlers
  server = setupServer(...(config.handlers || []));

  // Setup global test hooks
  beforeAll(async () => {
    server.listen();
    await config.beforeAll?.();
  });

  afterEach(() => {
    cleanup();
    server.resetHandlers();
    config.afterEach?.();
  });

  afterAll(async () => {
    server.close();
    await config.afterAll?.();
  });

  return {
    providers: config.providers || [],
    server,
  };
}

// Export a hook to access the server in tests
export function useTestServer() {
  if (!server) {
    throw new Error("Test server not initialized. Call setupTestUtils first.");
  }
  return server;
}

